trait Greet {
    fn hello(&self) -> String;
}

struct Person { name: String }
struct Robot  { id: u32 }

impl Greet for Person {
    fn hello(&self) -> String {
        format!("Hi, I'm {}", self.name)
    }
}
impl Greet for Robot {
    fn hello(&self) -> String {
        format!("BEEP. I AM ROBOT {}.", self.id)
    }
}

fn main() {
    let p = Person { name: String::from("Alice") };
    let r = Robot { id: 42 };
    println!("{}", p.hello());
    println!("{}", r.hello());
}

trait Summary {
    fn title(&self) -> String;
    fn preview(&self) -> String {
        format!("{}...", &self.title()[..20.min(self.title().len())])
    }
}

struct Article { title: String }

impl Summary for Article {
    fn title(&self) -> String { self.title.clone() }
    // preview() uses the default
}

fn main() {
    let a = Article { title: String::from("Rust is Amazing") };
    println!("{}", a.title());
    println!("{}", a.preview());
}

use std::fmt::Display;

fn print_twice<T: Display>(x: T) {
    println!("{}", x);
    println!("{}", x);
}

fn main() {
    print_twice(42);
    print_twice("hello");
    print_twice(3.14);
}

use std::fmt::{Display, Debug};

fn describe<T: Display + Debug>(x: T) {
    println!("Display: {}", x);
    println!("Debug:   {:?}", x);
}

fn main() {
    describe(42);
    describe("hello");
}

use std::fmt;

struct Point { x: f64, y: f64 }

impl fmt::Display for Point {
    fn fmt(&self, f: &mut fmt::Formatter) -> fmt::Result {
        write!(f, "({:.1}, {:.1})", self.x, self.y)
    }
}

fn main() {
    let p = Point { x: 3.0, y: 4.0 };
    println!("{}", p);
    println!("{}", format!("Point is {}", p));
}

use std::fmt::Display;

fn largest_display<T>(list: &[T]) -> &T
where
    T: PartialOrd + Display,
{
    let mut largest = &list[0];
    for item in list {
        if item > largest {
            largest = item;
        }
    }
    largest
}

fn main() {
    let numbers = vec![34, 50, 25, 100, 65];
    println!("largest: {}", largest_display(&numbers));
}

trait Animal {
    fn sound(&self) -> &str;
}
struct Dog;
struct Cat;
impl Animal for Dog { fn sound(&self) -> &str { "Woof" } }
impl Animal for Cat { fn sound(&self) -> &str { "Meow" } }

fn main() {
    let animals: Vec<Box<dyn Animal>> = vec![
        Box::new(Dog),
        Box::new(Cat),
        Box::new(Dog),
    ];
    for a in &animals {
        println!("{}", a.sound());
    }
}

#[derive(Debug, Clone, PartialEq)]
struct Point { x: f64, y: f64 }

fn main() {
    let p1 = Point { x: 1.0, y: 2.0 };
    let p2 = p1.clone();
    println!("{:?}", p1);
    println!("equal: {}", p1 == p2);
}
